mapper.select:
SELECT b.img_size, b.img_url
FROM tb_rcmmd_prefer_genre_similar_track a JOIN tb_map_img_rcmmd_img b ON a.svc_genre_id = b.img_content_id AND a.disp_sn = b.disp_sn AND a.rcmmd_prefer_genre_similar_track_id = #{recommendId}
FROM tb_rcmmd_mforu a JOIN tb_map_img_rcmmd_img b ON a.svc_genre_id = b.img_content_id AND a.disp_sn = b.disp_sn AND a.rcmmd_mforu_id = #{recommendId}
AND b.img_content_type = 'GENRE' AND b.rcmmd_type_id = #{recommendType} AND b.os_type = #{osType} AND b.img_disp_type = #{imageType} JOIN ( SELECT CASE DAYOFWEEK(NOW()) WHEN '1' THEN 'SUN' WHEN '2' THEN 'MON' WHEN '3' THEN 'TUE' WHEN '4' THEN 'WED' WHEN '5' THEN 'THU' WHEN '6' THEN 'FRI' WHEN '7' THEN 'SAT' END AS dfk_type UNION SELECT 'EVERY' ) c ON b.dfk_type = c.dfk_type ORDER BY a.disp_sn
